1	const countLiveNeighbors = (grid: boolean[][], r: number, c: number): number => {
2	  let count = 0;
3	  for (let dr = -1; dr <= 1; dr++) {
4	    for (let dc = -1; dc <= 1; dc++) {
5	      if (dr === 0 && dc === 0) continue;
6	      const nr = r + dr;
7	      const nc = c + dc;
8	      if (nr >= 0 && nr < grid.length && nc >= 0 && nc < grid[nr].length && grid[nr][nc]) {
9	        count++;
10	      }
11	    }
12	  }
13	  return count;
14	};
15	
16	const cellNextState = (cell: boolean, neighbors: number): boolean =>
17	  cell ? neighbors === 2 || neighbors === 3 : neighbors === 3;
18	
19	export function nextGeneration(grid: boolean[][]): boolean[][] {
20	  return grid.map((row, r) =>
21	    row.map((cell, c) => cellNextState(cell, countLiveNeighbors(grid, r, c)))
22	  );
23	}
