it("should transform a horizontal blinker back to a vertical blinker", () => {
  const horizontalBlinker = [
    [false, true,  false],
    [false, true,  false],
    [false, true,  false],
  ];
  const verticalBlinker = [
    [false, false, false],
    [true,  true,  true],
    [false, false, false],
  ];
